#!/usr/bin/env node
import "../_dnt.polyfills.js";
import * as dntShim from "../_dnt.shims.js";
import * as path from "../deps/jsr.io/@std/path/1.1.4/mod.js";
import FileCookieStore from "tough-cookie-file-store";
import YahooFinance from "../src/index.js";
import { ExtendedCookieJar } from "../src/lib/cookieJar.js";
import pkg from "../deno.js";
import { getModuleNames, runCli, } from "../src/lib/cli.js";
const moduleNames = getModuleNames(YahooFinance.prototype);
// moduleNames.push("_chart"); // modules in development
function getCookiePath() {
    const home = dntShim.Deno.env.get("HOME");
    if (!home)
        throw new Error("HOME environment variable is not set");
    return path.join(home, ".yf2-cookies.json");
}
function ensurePrivateFile(filePath) {
    try {
        dntShim.Deno.writeTextFileSync(filePath, "", { createNew: true });
    }
    catch (error) {
        if (!(error instanceof dntShim.Deno.errors.AlreadyExists))
            throw error;
    }
    try {
        dntShim.Deno.chmodSync(filePath, 0o600);
    }
    catch {
        // chmod is unsupported on Windows; best-effort only.
    }
}
function createClient(logger) {
    const cookiePath = getCookiePath();
    ensurePrivateFile(cookiePath);
    const cookieJar = new ExtendedCookieJar(new FileCookieStore(cookiePath));
    return new YahooFinance({
        cookieJar,
        logger,
        suppressNotices: ["yahooSurvey"],
    });
}
async function main() {
    const exitCode = await runCli({
        args: dntShim.Deno.args,
        version: pkg.version,
        moduleNames,
        createClient,
        readStdin: () => new Response(dntShim.Deno.stdin.readable).text(),
        stdoutIsTerminal: () => dntShim.Deno.stdout.isTerminal(),
    });
    dntShim.Deno.exit(exitCode);
}
if (globalThis[Symbol.for("import-meta-ponyfill-esmodule")](import.meta).main) {
    main();
}
